const original = $('When Executed by Another Workflow').first().json;

// Current item should be the result coming out of the approval IF path.
// Usually this contains something like:
// {
//   data: {
//     approved: true,
//     ...
//   }
// }
const approvalResult = $json ?? {};

const approvalData = approvalResult.data ?? {};
const approvalApproved = approvalData.approved ?? null;

return [
  {
    json: {
      // Bring forward the original payload from the parent flow
      clinic: original.clinic,
      sheetName: original.sheetName,
      address: original.address,
      endRow: original.endRow,

      orderCount: original.orderCount,
      expectedRows: original.expectedRows,

      hasOrders: original.hasOrders,
      readyForSubflow: original.readyForSubflow,

      driveId: original.driveId,
      itemsId: original.itemsId,
      currentExcelDriveId: original.currentExcelDriveId,
      startDate: original.startDate,

      checkedRows: original.checkedRows,
      actualOrderRows: original.actualOrderRows,

      // Approval details from the mismatch approval email
      mismatchApprovalApproved: approvalApproved,
      mismatchApprovalResponse: approvalData,

      // Status for the next re-check
      sourceStatus: approvalApproved === true
        ? 'RecheckAfterMismatchApproval'
        : 'MismatchApprovalNotApproved',

      // Handy message for debugging
      message: approvalApproved === true
        ? `${original.clinic}: mismatch approval received. Rechecking folder.`
        : `${original.clinic}: mismatch approval was not approved.`,
    },
  },
];

const original = $('When Executed by Another Workflow').first().json;
const approval = $json.data ?? {};

return [
  {
    json: {
      ...original,
      clinicApprovalApproved: approval.approved === true,
      clinicApprovalResponse: approval,
      sourceStatus: 'ClinicApprovedForCsvExport'
    }
  }
];

const original = $('Bring Forward Clinic Payload').first().json;

// Prefer displayed Excel text, fallback to raw values
const values = Array.isArray($json.text) ? $json.text : $json.values;

if (!Array.isArray(values)) {
  throw new Error('Graph response does not contain text or values array');
}

if (values.length < 2) {
  throw new Error('Excel range does not contain header row and data rows');
}

const headers = values[0];
const dataRows = values.slice(1);

// Remove fully blank rows
const nonBlankRows = dataRows.filter(row =>
  row.some(cell => cell !== null && cell !== undefined && String(cell).trim() !== '')
);

if (nonBlankRows.length !== original.orderCount) {
  throw new Error(
    `CSV row count mismatch for ${original.clinic}. Expected ${original.orderCount}, got ${nonBlankRows.length}`
  );
}

function escapeCsv(value) {
  if (value === null || value === undefined) return '';

  const stringValue = String(value);

  if (
    stringValue.includes(',') ||
    stringValue.includes('"') ||
    stringValue.includes('\n') ||
    stringValue.includes('\r')
  ) {
    return `"${stringValue.replace(/"/g, '""')}"`;
  }

  return stringValue;
}

const csv = [
  headers.map(escapeCsv).join(','),
  ...nonBlankRows.map(row =>
    headers.map((_, index) => escapeCsv(row[index])).join(',')
  )
].join('\r\n');

const clinic = original.clinic;
const startDate = original.startDate;
const fileName = `${clinic}_MedOrders_${startDate}.csv`;

return [
  {
    json: {
      ...original,
      csvFileName: fileName,
      csvRowCount: nonBlankRows.length,
      csvHeaderCount: headers.length,
      csvSourceUsed: Array.isArray($json.text) ? 'text' : 'values',
      sourceStatus: 'CsvCreated'
    },
    binary: {
      data: {
        data: Buffer.from(csv, 'utf8').toString('base64'),
        mimeType: 'text/csv',
        fileName
      }
    }
  }
];

const items = $input.all();

if (!items.length) {
  throw new Error('No PDF files found to combine');
}

const first = items[0];

const output = {
  json: {
    ...first.json,
    pdfCountForZip: items.length,
    zipFileName: `${first.json.clinic}_Scripts_${first.json.startDate}.zip`,
    sourceStatus: 'PdfFilesCombinedForZip'
  },
  binary: {}
};

items.forEach((item, index) => {
  if (!item.binary?.data) {
    throw new Error(`Missing binary data on PDF item ${index + 1}`);
  }

  const binaryKey = `PDF_${index + 1}`;

  output.binary[binaryKey] = {
    ...item.binary.data,
    fileName: item.binary.data.fileName || item.json.pdfFileName || `script_${index + 1}.pdf`,
    mimeType: item.binary.data.mimeType || 'application/pdf'
  };
});

// This gives the Compression node a dynamic list of fields to zip
output.json.binaryFieldsToZip = Object.keys(output.binary).join(',');

return [output];

const csvItem = $('ExceltoCSV').first();
const zipItem = $input.first();

if (!csvItem.binary?.data) {
  throw new Error('CSV binary not found from ExceltoCSV');
}

const zipBinaryKeys = Object.keys(zipItem.binary ?? {});

if (!zipBinaryKeys.length) {
  throw new Error('ZIP binary not found from Compression');
}

const zipKey = zipBinaryKeys[0];
const zipBinary = zipItem.binary[zipKey];

return [
  {
    json: {
      ...csvItem.json,
      ...zipItem.json,

      attachmentCount: 2,
      csvAttachmentName: csvItem.binary.data.fileName || csvItem.json.csvFileName,
      scriptsAttachmentName: zipBinary.fileName || zipItem.json.zipFileName,

      sourceStatus: 'ReadyToEmailCompoundLab'
    },
    binary: {
      med_orders_csv: {
        ...csvItem.binary.data,
        fileName: csvItem.binary.data.fileName || csvItem.json.csvFileName || 'MedOrders.csv',
        mimeType: csvItem.binary.data.mimeType || 'text/csv'
      },

      scripts_zip: {
        ...zipBinary,
        fileName: zipBinary.fileName || zipItem.json.zipFileName || `${csvItem.json.clinic}_Scripts_${csvItem.json.startDate}.zip`,
        mimeType: zipBinary.mimeType || 'application/zip'
      }
    }
  }
];

